import React, { useState, useEffect, useMemo } from 'react';
import { NotebookItem, AppSettings } from '../types';
import { Trash2, Quote, Book, Clock, ImageDown, Volume2, X as XIcon, Play, Zap, Notebook as NotebookIcon, ChevronDown, Settings2, Type, Loader2, AlertCircle, ChevronUp, Languages, ChevronLeft, ChevronRight, ArrowUpDown } from 'lucide-react';
import { generateSpeech, getQuickDefinition, translateText } from '../services/gemini';

interface Props {
  items: NotebookItem[];
  onDelete: (id: string) => void;
  onBulkDelete: (ids: string[]) => void;
  onUpdateComment: (id: string, comment: string) => void;
  onBatchUpdateDefinitions?: (updates: Record<string, string>) => void;
  settings: AppSettings;
}

type FilterType = 'all' | 'word' | 'phrase' | 'sentence';
type SortOrder = 'newest' | 'oldest' | 'az' | 'za';

export const Notebook: React.FC<Props> = ({ items, onDelete, onBulkDelete, onUpdateComment, onBatchUpdateDefinitions, settings }) => {
  const fontStyle = { fontFamily: settings.font ? `"${settings.font}", sans-serif` : 'inherit' };
  const [playingId, setPlayingId] = useState<string | null>(null);
  const [activeFilter, setActiveFilter] = useState<FilterType>('all');
  const [sortOrder, setSortOrder] = useState<SortOrder>('newest');

  const [isFlashcardMode, setIsFlashcardMode] = useState(false);
  const [currentFlashcardIndex, setCurrentFlashcardIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [isPreparingCards, setIsPreparingCards] = useState(false);
  const [fetchingIds, setFetchingIds] = useState<Set<string>>(new Set());

  // Local cache for definitions and translations during the current study session
  const [sessionDefinitions, setSessionDefinitions] = useState<Record<string, string>>({});
  const [sessionTranslations, setSessionTranslations] = useState<Record<string, string>>({});
  const [showTranslatedCard, setShowTranslatedCard] = useState(false);
  const [isTranslatingCard, setIsTranslatingCard] = useState(false);

  const filteredItems = useMemo(() => {
      let result = activeFilter === 'all' 
        ? [...items] 
        : items.filter(item => item.type === activeFilter);

      switch (sortOrder) {
          case 'newest':
              result.sort((a, b) => b.timestamp - a.timestamp);
              break;
          case 'oldest':
              result.sort((a, b) => a.timestamp - b.timestamp);
              break;
          case 'az':
              result.sort((a, b) => a.text.localeCompare(b.text));
              break;
          case 'za':
              result.sort((a, b) => b.text.localeCompare(a.text));
              break;
      }
      return result;
  }, [items, activeFilter, sortOrder]);

  const pcmToWav = (base64Pcm: string) => {
    const binaryString = atob(base64Pcm);
    const len = binaryString.length;
    const buffer = new ArrayBuffer(44 + len);
    const view = new DataView(buffer);
    const writeString = (v: DataView, offset: number, str: string) => {
      for (let i = 0; i < str.length; i++) v.setUint8(offset + i, str.charCodeAt(i));
    };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + len, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, 24000, true);
    view.setUint32(28, 48000, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, len, true);
    const bytes = new Uint8Array(buffer, 44);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
    return new Blob([buffer], { type: 'audio/wav' });
  };

  const playPronunciation = async (id: string, text: string) => {
     if (playingId) return;
     setPlayingId(id);
     let audioUrl: string | null = null;
     try {
          const b64 = await generateSpeech(text, "Puck");
          if(b64) {
             const blob = pcmToWav(b64);
             audioUrl = URL.createObjectURL(blob);
             const audio = new Audio(audioUrl);
             audio.onended = () => {
                 setPlayingId(null);
                 if (audioUrl) URL.revokeObjectURL(audioUrl);
             };
             await audio.play();
          } else {
             setPlayingId(null);
          }
      } catch (e) {
          console.error("Playback failed:", e);
          setPlayingId(null);
          if (audioUrl) URL.revokeObjectURL(audioUrl);
      }
  };

  const generateStickyNote = (item: NotebookItem) => {
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      if (!ctx) return;
      canvas.width = 800;
      canvas.height = 800;
      ctx.fillStyle = '#050505'; 
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      ctx.strokeStyle = '#1f2937';
      ctx.lineWidth = 1;
      for(let i=0; i < canvas.width; i+=40) { ctx.beginPath(); ctx.moveTo(i, 0); ctx.lineTo(i, canvas.height); ctx.stroke(); }
      for(let i=0; i < canvas.height; i+=40) { ctx.beginPath(); ctx.moveTo(0, i); ctx.lineTo(canvas.width, i); ctx.stroke(); }
      const margin = 50;
      const contentWidth = canvas.width - (margin * 2);
      ctx.fillStyle = '#00f3ff';
      const cornerSize = 8;
      ctx.fillRect(margin, margin, cornerSize, cornerSize);
      ctx.fillRect(canvas.width - margin - cornerSize, margin, cornerSize, cornerSize);
      ctx.fillRect(margin, canvas.height - margin - cornerSize, cornerSize, cornerSize);
      ctx.fillRect(canvas.width - margin - cornerSize, canvas.height - margin - cornerSize, cornerSize, cornerSize);
      let y = margin + 40;
      ctx.fillStyle = '#ff003c';
      ctx.font = 'bold 16px "Courier New", monospace';
      ctx.textAlign = 'left';
      ctx.fillText(`// LOG_DATE: ${new Date(item.timestamp).toISOString().split('T')[0]}`, margin, y);
      y += 25;
      if (item.bookTitle) {
          ctx.fillStyle = '#00f3ff';
          ctx.font = 'bold 20px "Courier New", monospace';
          const authorText = item.bookAuthor ? ` | ${item.bookAuthor}` : '';
          ctx.fillText(`BOOK: ${item.bookTitle.toUpperCase().substring(0, 20)}${authorText.substring(0, 15)}`, margin, y);
          y += 25;
      }
      ctx.strokeStyle = '#334155'; ctx.lineWidth = 1; ctx.beginPath(); ctx.moveTo(margin, y); ctx.lineTo(canvas.width - margin, y); ctx.stroke();
      y += 40;
      let fontSize = 32;
      const mainFont = settings.font ? `"${settings.font}", sans-serif` : 'Georgia';
      ctx.font = `${fontSize}px ${mainFont}`;
      const words = item.text.split(' ');
      let lines: string[] = [];
      let line = '';
      const calculateLines = () => {
         lines = []; line = '';
         for(let n = 0; n < words.length; n++) {
            const testLine = line + words[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
              lines.push(line); line = words[n] + ' ';
            } else { line = testLine; }
         }
         lines.push(line);
      };
      calculateLines();
      const maxHeight = 350;
      while (lines.length * (fontSize * 1.5) > maxHeight && fontSize > 14) {
          fontSize -= 2; ctx.font = `${fontSize}px ${mainFont}`; calculateLines();
      }
      ctx.fillStyle = '#334155'; ctx.font = `${fontSize * 3}px ${mainFont}`;
      ctx.fillText('"', margin - 20, y + fontSize);
      ctx.fillStyle = '#e2e8f0'; ctx.font = `${fontSize}px ${mainFont}`;
      const lineHeight = fontSize * 1.5;
      for (let i = 0; i < lines.length; i++) { ctx.fillText(lines[i], margin, y); y += lineHeight; }
      y += 30;
      if (item.definition) {
          ctx.fillStyle = '#22d3ee'; ctx.font = 'bold 14px "Courier New", monospace';
          ctx.fillText(">> ANALYSIS_OUTPUT:", margin, y); y += 20;
          ctx.fillStyle = '#94a3b8'; ctx.font = '14px "Courier New", monospace';
          const defWords = item.definition.split(' ');
          let defLine = '';
          for(let n = 0; n < defWords.length; n++) {
            const testLine = defLine + defWords[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
               ctx.fillText(defLine, margin, y); defLine = defWords[n] + ' '; y += 18;
            } else { defLine = testLine; }
         }
         ctx.fillText(defLine, margin, y); y += 35;
      }
      if (item.comment) {
          ctx.fillStyle = '#f59e0b'; ctx.font = 'bold 14px "Courier New", monospace';
          ctx.fillText(">> USER_ANNOTATION:", margin, y); y += 20;
          ctx.fillStyle = '#b45309'; ctx.font = 'italic 14px "Courier New", monospace';
          const commentWords = item.comment.split(' ');
          let commentLine = '';
          for(let n = 0; n < commentWords.length; n++) {
            const testLine = commentLine + commentWords[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
               ctx.fillText(commentLine, margin, y); commentLine = commentWords[n] + ' '; y += 18;
            } else { commentLine = testLine; }
         }
         ctx.fillText(commentLine, margin, y); y += 35;
      }
      ctx.fillStyle = '#1f2937'; ctx.font = '10px "Courier New", monospace'; ctx.textAlign = 'center';
      ctx.fillText("FLASH_NOTES // NEURAL INTERFACE CONTENT", canvas.width / 2, canvas.height - 20);
      const link = document.createElement('a');
      link.download = `flash-note-${item.id}.png`;
      link.href = canvas.toDataURL();
      link.click();
  };

  const startFlashcards = () => {
      if (filteredItems.length === 0) return;
      setCurrentFlashcardIndex(0);
      setIsFlipped(false);
      setShowTranslatedCard(false);
      setIsFlashcardMode(true);
      setSessionDefinitions({});
      setSessionTranslations({});
  };

  const currentStudyItem = filteredItems[currentFlashcardIndex];

  // Logic for switching between original language definition and translation
  const originalDef = (currentStudyItem?.id && sessionDefinitions[currentStudyItem.id]) || currentStudyItem?.definition;
  const translatedDef = currentStudyItem?.id ? sessionTranslations[currentStudyItem.id] : null;
  const activeDefinition = showTranslatedCard ? translatedDef : originalDef;
  const isCurrentItemLoading = currentStudyItem?.id && fetchingIds.has(currentStudyItem.id);

  useEffect(() => {
    if (isFlashcardMode && currentStudyItem && !currentStudyItem.definition && !sessionDefinitions[currentStudyItem.id] && !fetchingIds.has(currentStudyItem.id)) {
        const fetchDef = async () => {
            const itemId = currentStudyItem.id;
            setFetchingIds(prev => new Set(prev).add(itemId));
            try {
                // Always fetch in source language first for Flashcards
                // Note: We only update session cache, NOT the database (removed onBatchUpdateDefinitions)
                const def = await getQuickDefinition(currentStudyItem.text, "the same language as the text");
                setSessionDefinitions(prev => ({ ...prev, [itemId]: def }));
            } catch (e: any) {
                console.error("Failed to pre-fetch definition:", e);
                setSessionDefinitions(prev => ({ ...prev, [itemId]: "ERR_DECODE: Signal interference." }));
            } finally {
                setFetchingIds(prev => {
                    const next = new Set(prev);
                    next.delete(itemId);
                    return next;
                });
            }
        };
        fetchDef();
    }
  }, [isFlashcardMode, currentFlashcardIndex, currentStudyItem]);

  const handleTranslateFlashcard = async (e: React.MouseEvent) => {
      e.stopPropagation();
      if (!currentStudyItem || isTranslatingCard) return;

      if (showTranslatedCard) {
          setShowTranslatedCard(false);
          return;
      }

      if (sessionTranslations[currentStudyItem.id]) {
          setShowTranslatedCard(true);
          return;
      }

      const textToTranslate = originalDef;
      if (!textToTranslate) return;

      setIsTranslatingCard(true);
      try {
          const targetLang = settings.targetLanguage === 'Original' ? 'English' : settings.targetLanguage;
          const trans = await translateText(textToTranslate, targetLang);
          setSessionTranslations(prev => ({ ...prev, [currentStudyItem.id]: trans }));
          setShowTranslatedCard(true);
      } catch (e) {
          console.error("Flashcard translation failed:", e);
      } finally {
          setIsTranslatingCard(false);
      }
  };

  const handleFlip = (item: NotebookItem) => {
      setIsFlipped(!isFlipped);
  };

  const formatAnalysisText = (text: string) => {
      if (!text) return null;
      return text.split('\n').map((line, i) => {
          const trimmed = line.trim();
          if (!trimmed) return <div key={i} className="h-2" />;
          const parts = trimmed.split(/(\*\*.*?\*\*)/g);
          return (
              <p key={i} className="mb-2">
                  {parts.map((part, pi) => {
                      if (part.startsWith('**') && part.endsWith('**')) {
                          return <span key={pi} className="text-[#ff003c] font-bold">{part.slice(2, -2)}</span>;
                      }
                      return part;
                  })}
              </p>
          );
      });
  };

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100 text-left relative" style={fontStyle}>
       <style>{`
          .perspective-1000 { perspective: 1000px; -webkit-perspective: 1000px; } 
          .backface-hidden { backface-visibility: hidden; -webkit-backface-visibility: hidden; z-index: 2; } 
          .rotate-y-180 { transform: rotateY(180deg); -webkit-transform: rotateY(180deg); } 
          .transform-style-3d { transform-style: preserve-3d; -webkit-transform-style: preserve-3d; }
          .custom-scrollbar-visible::-webkit-scrollbar { width: 6px; }
          .custom-scrollbar-visible::-webkit-scrollbar-track { background: rgba(0,0,0,0.3); border-radius: 3px; }
          .custom-scrollbar-visible::-webkit-scrollbar-thumb { background: #ff003c; border-radius: 3px; box-shadow: 0 0 10px rgba(255,0,60,0.5); }
          .custom-scrollbar-visible::-webkit-scrollbar-thumb:hover { background: #ff2b5c; }
       `}</style>

       <div className="sticky top-0 z-[160] bg-zinc-950/90 p-3 rounded-lg border border-zinc-800 flex items-center justify-between shadow-[0_4px_20px_rgba(0,0,0,0.6)] backdrop-blur-md mb-4">
           <div className="flex items-center gap-3 border-r border-zinc-800 pr-6">
               <NotebookIcon size={18} className="text-[#00f3ff]" />
               <span className="text-xs font-tech font-bold text-white tracking-[0.2em] uppercase">Mem_Log</span>
           </div>
           <div className="flex items-center gap-3 flex-1 justify-end">
               {!isFlashcardMode && (
                   <div className="flex items-center gap-2 bg-black/50 p-1 rounded-sm border border-zinc-800">
                        <div className="p-1.5 text-zinc-500"><Settings2 size={16} /></div>
                        <select 
                            value={activeFilter} 
                            onChange={(e) => setActiveFilter(e.target.value as FilterType)}
                            className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]"
                        >
                            <option value="all">ALL ITEMS</option>
                            <option value="word">WORDS</option>
                            <option value="phrase">PHRASES</option>
                            <option value="sentence">SENTENCES</option>
                        </select>
                        <div className="w-[1px] h-4 bg-zinc-700"></div>
                        <div className="p-1.5 text-zinc-500"><ArrowUpDown size={16} /></div>
                        <select 
                            value={sortOrder} 
                            onChange={(e) => setSortOrder(e.target.value as SortOrder)}
                            className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-[120px] bg-[#050505]"
                        >
                            <option value="newest">NEWEST</option>
                            <option value="oldest">OLDEST</option>
                            <option value="az">A-Z</option>
                            <option value="za">Z-A</option>
                        </select>
                   </div>
               )}
               <button onClick={isFlashcardMode ? () => setIsFlashcardMode(false) : startFlashcards} disabled={filteredItems.length === 0 || isPreparingCards} className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-xs font-black font-mono uppercase transition-all shadow-lg transform active:scale-95 ml-2 min-w-[120px] justify-center ${isFlashcardMode ? 'bg-zinc-800 text-zinc-400 border border-zinc-700 hover:text-white hover:border-white' : 'bg-[#00f3ff] text-black hover:bg-[#00c2cc] shadow-[0_0_15px_rgba(0,243,255,0.4)]'}`}>{isFlashcardMode ? <XIcon size={14} /> : (isPreparingCards ? <Loader2 size={14} className="animate-spin" /> : <Play size={14} fill="currentColor" />)}{isFlashcardMode ? "EXIT" : (isPreparingCards ? "SYNCING..." : "INITIATE")}</button>
           </div>
       </div>

       {isFlashcardMode && currentStudyItem ? (
           <div className="absolute inset-0 top-[72px] z-[150] bg-[#020202]/95 flex flex-col items-center justify-center p-6 animate-fade-in font-sans overflow-hidden">
                <div className="w-full max-w-2xl flex flex-col items-center justify-center -mt-8">
                  <div className="text-center mb-8 w-full animate-fade-in-up">
                      <h2 className="text-[#00f3ff] font-tech text-xs uppercase tracking-[0.7em] mb-3 animate-pulse font-black drop-shadow-[0_0_8px_rgba(0,243,255,0.4)]">Neural_Study_Session</h2>
                      <div className="flex items-center justify-center gap-4">
                          <div className="h-[1px] w-12 bg-gradient-to-r from-transparent to-[#00f3ff]/30"></div>
                          <p className="text-zinc-600 font-mono text-[9px] tracking-[0.2em] uppercase">Buffer_Index: {currentFlashcardIndex + 1} / {filteredItems.length}</p>
                          <div className="h-[1px] w-12 bg-gradient-to-l from-transparent to-[#00f3ff]/30"></div>
                      </div>
                  </div>

                  <div onClick={() => handleFlip(currentStudyItem)} className="relative w-full aspect-[16/9] max-h-[400px] perspective-1000 cursor-pointer group mb-10">
                      <div className={`relative w-full h-full transition-transform duration-700 transform-style-3d ${isFlipped ? 'rotate-y-180' : ''}`}>
                          <div className="absolute inset-0 backface-hidden bg-[#050505] border-2 border-[#00f3ff]/20 rounded-2xl flex flex-col items-center justify-center p-10 text-center shadow-[0_0_50px_rgba(0,0,0,1)] hover:border-[#00f3ff]/40 transition-colors overflow-hidden">
                              <div className="absolute top-6 left-6 text-[#00f3ff]/20"><Zap size={32} /></div>
                              <div className="absolute top-6 right-6 text-zinc-800 font-mono text-[8px] tracking-widest uppercase">Front_Layer</div>
                              <p className="text-xl md:text-2xl font-black text-white leading-relaxed font-serif italic max-w-lg">"{currentStudyItem.text}"</p>
                              <div className="absolute bottom-8 flex flex-col items-center gap-1 opacity-40 group-hover:opacity-100 transition-opacity">
                                  <p className="text-cyan-500 font-mono text-[8px] uppercase tracking-widest animate-bounce">Click to Flip_Interface</p>
                              </div>
                          </div>
                          <div className="absolute inset-0 backface-hidden rotate-y-180 bg-[#0a0a0c] border-2 border-[#ff003c]/20 rounded-2xl flex flex-col items-center justify-center p-10 text-center shadow-[0_0_50px_rgba(0,0,0,1)] hover:border-[#ff003c]/40 transition-colors overflow-hidden">
                              <div className="absolute top-6 right-6 flex items-center gap-2">
                                  <button onClick={handleTranslateFlashcard} disabled={isTranslatingCard || isCurrentItemLoading} className={`p-2 rounded-sm border transition-all ${showTranslatedCard ? 'bg-[#ff003c]/10 border-[#ff003c] text-[#ff003c]' : 'bg-zinc-900 border-zinc-800 text-zinc-500 hover:text-white'} ${isTranslatingCard ? 'animate-pulse' : ''}`} title={showTranslatedCard ? "Show Original Analysis" : "Translate Analysis"}>
                                      {isTranslatingCard ? <Loader2 size={12} className="animate-spin" /> : <Languages size={12} />}
                                  </button>
                                  <div className="text-zinc-800 font-mono text-[8px] tracking-widest uppercase">{showTranslatedCard ? 'Translation_Layer' : 'Back_Layer'}</div>
                              </div>
                              <div className="flex flex-col h-full w-full max-w-2xl text-left pt-6 pb-4">
                                  <div className="animate-fade-in flex flex-col h-full overflow-hidden">
                                      <h4 className="text-[#ff003c] font-mono text-[9px] uppercase tracking-[0.4em] mb-4 font-black border-b border-[#ff003c]/20 pb-2 shrink-0">{showTranslatedCard ? 'Translation_Output' : 'Analysis_Output'}:</h4>
                                      <div className="flex-1 overflow-hidden relative group/scroll flex">
                                          <div className="flex-1 overflow-y-auto custom-scrollbar-visible pr-4 font-mono text-sm leading-relaxed text-zinc-200 bg-black/40 p-4 rounded border border-zinc-900 shadow-inner">
                                              {isCurrentItemLoading || isTranslatingCard ? (
                                                  <div className="flex items-center gap-3 text-zinc-600 py-4">
                                                      <Loader2 size={16} className="animate-spin text-[#ff003c]" />
                                                      DECODING_DATA...
                                                  </div>
                                              ) : activeDefinition?.includes("ERR_500") ? (
                                                  <div className="bg-rose-950/20 border border-rose-900/50 p-4 rounded flex items-start gap-3">
                                                      <AlertCircle size={18} className="text-[#ff003c] shrink-0 mt-1" />
                                                      <div>
                                                          <p className="text-rose-400 font-mono text-xs uppercase font-bold mb-1">Signal Interrupt</p>
                                                          <p className="text-xs text-rose-500/80 font-mono leading-tight">{activeDefinition}</p>
                                                      </div>
                                                  </div>
                                              ) : (
                                                  <div className="animate-fade-in">
                                                      {formatAnalysisText(activeDefinition || "DATA_LINK_OFFLINE: Analysis unavailable.")}
                                                  </div>
                                              )}
                                              {currentStudyItem.comment && (
                                                  <div className="pt-4 mt-4 border-t border-zinc-800/50 animate-fade-in">
                                                      <h4 className="text-amber-500 font-mono text-[9px] uppercase tracking-[0.4em] mb-2 font-black">User_Annotation:</h4>
                                                      <p className="text-xs text-zinc-500 italic leading-relaxed">"{currentStudyItem.comment}"</p>
                                                  </div>
                                              )}
                                          </div>
                                          {!isCurrentItemLoading && (
                                              <div className="w-8 flex flex-col items-center justify-between py-2 border-l border-zinc-900 ml-2 shrink-0 opacity-40 hover:opacity-100 transition-opacity">
                                                  <div className="flex flex-col items-center gap-1"><ChevronUp size={14} className="text-[#ff003c]" /><div className="h-4 w-[1px] bg-[#ff003c]/30" /></div>
                                                  <span className="[writing-mode:vertical-lr] text-[8px] font-mono text-zinc-600 uppercase tracking-widest">Scroll_Data</span>
                                                  <div className="flex flex-col items-center gap-1"><div className="h-4 w-[1px] bg-[#ff003c]/30" /><ChevronDown size={14} className="text-[#ff003c]" /></div>
                                              </div>
                                          )}
                                      </div>
                                  </div>
                              </div>
                              <p className="absolute bottom-4 left-1/2 -translate-x-1/2 text-zinc-700 font-mono text-[8px] uppercase tracking-widest pointer-events-none">Return to Snippet_View</p>
                          </div>
                      </div>
                  </div>
                  <div className="flex items-center gap-16 animate-fade-in-up" style={{ animationDelay: '0.2s' }}>
                      <button onClick={(e) => { e.stopPropagation(); setIsFlipped(false); setShowTranslatedCard(false); setCurrentFlashcardIndex((prev) => (prev - 1 + filteredItems.length) % filteredItems.length); }} className="group flex flex-col items-center gap-2">
                         <div className="p-4 bg-zinc-900 border border-zinc-800 text-zinc-500 group-hover:text-[#00f3ff] group-hover:border-[#00f3ff] rounded-full transition-all group-hover:scale-110 shadow-lg"><ChevronLeft size={28} /></div>
                         <span className="text-[8px] font-mono text-zinc-700 group-hover:text-zinc-500 uppercase tracking-widest">Previous</span>
                      </button>
                      <button onClick={(e) => { e.stopPropagation(); setIsFlipped(false); setShowTranslatedCard(false); setCurrentFlashcardIndex((prev) => (prev + 1) % filteredItems.length); }} className="group flex flex-col items-center gap-2">
                         <div className="p-4 bg-zinc-900 border border-zinc-800 text-zinc-500 group-hover:text-[#00f3ff] group-hover:border-[#00f3ff] rounded-full transition-all group-hover:scale-110 shadow-lg"><ChevronRight size={28} /></div>
                         <span className="text-[8px] font-mono text-zinc-700 group-hover:text-zinc-500 uppercase tracking-widest">Next</span>
                      </button>
                  </div>
              </div>
           </div>
       ) : (
           <>
               {items.length === 0 ? (
                   <div className="flex-1 flex flex-col items-center justify-center text-zinc-600 font-mono gap-4 animate-fade-in"><Book size={48} className="opacity-20" /><p className="text-sm">NO_DATA_LOGGED</p><p className="text-[10px] text-zinc-700 max-w-xs text-center uppercase tracking-widest">Right-click text selection in reader to populate your lexicon.</p></div>
               ) : filteredItems.length === 0 ? (
                   <div className="flex-1 flex flex-col items-center justify-center text-zinc-700 font-mono gap-2 animate-fade-in"><p className="text-xs uppercase tracking-widest opacity-50">BUFFER_EMPTY_FOR_{activeFilter === 'all' ? 'ALL_ITEMS' : activeFilter.toUpperCase() + 'S'}</p></div>
               ) : (
                   <div className="flex-1 overflow-y-auto pr-2 pb-10 custom-scrollbar space-y-4">
                       {filteredItems.map((item, idx) => {
                           const typeColor = item.type === 'phrase' ? 'text-[#ff003c]' : item.type === 'word' ? 'text-cyan-400' : 'text-[#00f3ff]';
                           return (
                           <div key={item.id} className="bg-[#0a0a0c] border rounded-lg p-5 relative group transition-all animate-fade-in-up pr-14 border-zinc-800 hover:border-zinc-700" style={{ animationDelay: `${idx * 0.05}s` }}>
                               <div className="absolute top-2 right-2 flex flex-col gap-1 z-20">
                                   <button onClick={() => playPronunciation(item.id, item.text)} disabled={!!playingId} className={`p-1.5 rounded border border-transparent transition-all mb-1 ${playingId === item.id ? 'text-[#00f3ff] bg-[#00f3ff]/10 animate-pulse' : 'text-zinc-600 hover:text-[#00f3ff] bg-zinc-900/50 hover:bg-[#00f3ff]/10'}`} title="Pronounce"><Volume2 size={14} /></button>
                                   <button onClick={() => generateStickyNote(item)} className="p-1.5 text-zinc-600 hover:text-[#00f3ff] bg-zinc-900/50 hover:bg-[#00f3ff]/10 rounded border border-transparent hover:border-[#00f3ff]/20 transition-all" title="Generate Visual Log"><ImageDown size={14} /></button>
                                   <button onClick={() => onDelete(item.id)} className="p-1.5 text-zinc-600 hover:text-[#ff003c] bg-zinc-900/50 hover:bg-[#ff003c]/10 rounded border border-transparent hover:border-[#ff003c]/20 transition-all" title="Purge Entry"><Trash2 size={14} /></button>
                               </div>
                               <div className="flex items-start gap-4">
                                   <div className="mt-1 shrink-0">{item.type === 'sentence' ? <Quote size={16} className="text-[#00f3ff]" /> : item.type === 'phrase' ? <Zap size={16} className="text-[#ff003c]" /> : <Type size={16} className="text-cyan-400" />}</div>
                                   <div className="flex-1 min-w-0 space-y-3">
                                       <div><p className="text-white text-base font-medium leading-relaxed font-serif break-words">"{item.text}"</p>
                                           <div className="flex items-center gap-3 mt-2 flex-wrap">
                                               <span className={`text-[9px] font-mono uppercase tracking-wide bg-zinc-900 px-1.5 py-0.5 rounded border border-zinc-800 ${typeColor}`}>{item.type}</span>
                                               {item.bookTitle && <span className="text-[10px] font-mono text-cyan-500/60 truncate max-w-[150px]">{item.bookTitle}</span>}
                                               {item.sourceChapter && <span className="text-[10px] font-mono text-zinc-600 truncate max-w-[200px]">CH: {item.sourceChapter}</span>}
                                               <span className="text-[10px] font-mono text-zinc-700 flex items-center gap-1"><Clock size={10} />{new Date(item.timestamp).toLocaleDateString()}</span>
                                           </div>
                                       </div>
                                       {item.definition && (
                                           <div className="bg-black/50 p-3 rounded border border-zinc-900"><p className="text-sm text-zinc-500 italic font-mono leading-relaxed">{item.definition}</p></div>
                                       )}
                                       <div className="mt-2"><textarea placeholder="Add neural annotations..." value={item.comment || ''} onChange={(e) => onUpdateComment(item.id, e.target.value)} className="w-full bg-[#050505] border border-zinc-800 rounded p-2 text-xs text-zinc-400 focus:border-[#00f3ff] focus:outline-none transition-colors min-h-[50px] font-mono" /></div>
                                   </div>
                               </div>
                           </div>
                           );
                       })}
                   </div>
               )}
           </>
       )}
    </div>
  );
};
